class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe: our model explicitly keeps "Discriminator" as
        // the discriminator property name (see ProductContext), so c.Discriminator
        // still resolves against both old and new documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos: sync I/O (ToList, SaveChanges, etc.) now throws.
        // Use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

